ReportUtil = {}

local function getPlayerGameTime(player)
    local minute = (os.time() - player.property.loginTime) / 60
    if minute <= 3 then
        return "0_3_minutes"
    elseif minute > 3 and minute <= 15 then
        return "3_15_minutes"
    elseif minute > 15 and minute <= 60 then
        return "15_60_minutes"
    elseif minute > 60 and minute <= 90 then
        return "60_90_minutes"
    elseif minute > 90 and minute <= 120 then
        return "90_120_minutes"
    else
        return "120_INF_minutes"
    end
end

local function getPlayerGold(player)
    local gold = tonumber(tostring(player.property.gold))
    if gold <= 10000 then
        return "0_10K_gold"
    elseif gold > 10000 and gold <= 100000 then
        return "10K_100K_gold"
    elseif gold > 100000 and gold <= 2000000 then
        return "100K_2M_gold"
    elseif gold > 2000000 and gold <= 150000000 then
        return "2M_150M_gold"
    else
        return "150M_INF_gold"
    end
end

function ReportUtil.reportStartAdvanced(player, id)
