end

function ReportUtil.reportAdvancedResult(player, isWin, id)
    if isWin then
        GameAnalytics:design(player.userId, 1, { "boss_stage", id, id })
        LogUtil.log("ReportUtil.reportAdvancedResult " .. id)
    end
end

function ReportUtil.onDoReport(player, builder)
    if builder:getParam("AddDiamond") then
        ReportUtil.reportAddDiamond(player)
    elseif builder:getParam("ClickPretend") then
        ReportUtil.reportClickPretend(player, builder:getParam("ClickPretend"))
    elseif builder:getParam("ClickWorkout") then
        ReportUtil.reportClickWorkout(player, builder:getParam("ClickWorkout"))
    elseif builder:getParam("ClickAdvance") then
        ReportUtil.reportClickAdvance(player)
    elseif builder:getParam("ClickPayShop") then
        ReportUtil.reportClickPayShop(player)
    elseif builder:getParam("ClickSkin") then
        ReportUtil.reportClickSkin(player)
    elseif builder:getParam("doGrab") then
        ReportUtil.reportDoGrab(player, builder:getParam("doGrab"))
    elseif builder:getParam("ClickGold") then
        ReportUtil.reportClickGold(player, builder:getParam("ClickGold"))
    elseif builder:getParam("ClickVip") then
        ReportUtil.reportClickVip(player, builder:getParam("ClickVip"))
    elseif builder:getParam("ClickWatchAd") then
        ReportUtil.reportClickWatchAd(player)
    end
end

