function ReportUtil.reportSelectSkin(player, index)
    local key = ""

    local sex = player:getSex()
    if sex == 1 then
        key = "def_boy"
    else
        key = "def_girl"
    end

    local result = ""
    if index == Define.SelectSkinType.Default then
        result = "default"
    else
        result = "new"
    end

    local parts = { key, result }
    GameAnalytics:design(player.userId, 1, parts)

    LogUtil.log(string.format("ReportUtil.reportSelectSkin %s %s", key, result))
end

function ReportUtil.reportBuyPayItem(player, itemType, success)
    success = success or false
    if success then
        local parts = { "buy_vip", "Click " .. itemType, "Buy " .. itemType }
        GameAnalytics:design(player.userId, 1, parts)
    else
        local parts = { "buy_vip", "Click " .. itemType, "Buy " .. -1 }
        GameAnalytics:design(player.userId, 1, parts)
    end

    LogUtil.log("ReportUtil.reportBuyPayItem " .. itemType)

    ReportUtil.reportBuyPayShop(player)
end

function ReportUtil.reportBuySkinId(player, id, success)
    success = success or false
    if success then
        local parts = { "buy_skin", "Click " .. id, "Buy " .. id }
        GameAnalytics:design(player.userId, 1, parts)
    else
